## 4. Ensure Sufficient Color Contrast

Use the contrast calculator for all text and interactive elements:

```csharp
public class AccessibleColorScheme
{
    public static void ValidateColors()
    {
        var background = Colors.White;
        var textColor = Color.FromRgb(85, 85, 85);
        var linkColor = Color.FromRgb(0, 102, 204);

        // Normal text (18pt or smaller)
        var textContrast = ContrastCalculator.CalculateContrastRatio(
            textColor, background);
        Debug.Assert(textContrast >= 4.5, 
            $"Text contrast {textContrast:F2} fails WCAG AA");

        // Large text (18pt+ or 14pt+ bold)
        var headingColor = Color.FromRgb(51, 51, 51);
        var headingContrast = ContrastCalculator.CalculateContrastRatio(
            headingColor, background);
        Debug.Assert(headingContrast >= 3.0, 
            $"Heading contrast {headingContrast:F2} fails WCAG AA");

        // Interactive elements
        var linkContrast = ContrastCalculator.CalculateContrastRatio(
            linkColor, background);
        Debug.Assert(linkContrast >= 4.5, 
            $"Link contrast {linkContrast:F2} fails WCAG AA");
    }
}
```

## 5. Provide Clear Focus Indicators

Focus must always be visible with sufficient contrast:

```csharp
public class AccessibleButton : SkiaButton
{
    protected override void OnPaintSurface(SKCanvas canvas, int width, 
        int height)
    {
        base.OnPaintSurface(canvas, width, height);

        if (IsFocused)
        {
            // Calculate focus ring color with 3:1 contrast
            var backgroundColor = GetEffectiveBackgroundColor();
            var focusColor = GetContrastingColor(backgroundColor, 3.0);

            using var paint = new SKPaint
            {
                Style = SKPaintStyle.Stroke,
                Color = focusColor.ToSKColor(),
                StrokeWidth = 3,
                IsAntialias = true
            };

            var rect = new SKRect(2, 2, width - 2, height - 2);
            canvas.DrawRoundRect(rect, CornerRadius, CornerRadius, paint);
        }
    }

    private Color GetContrastingColor(Color background, double minRatio)
    {
        // Return black or white, whichever provides better contrast
        var blackContrast = ContrastCalculator.CalculateContrastRatio(
            Colors.Black, background);
        var whiteContrast = ContrastCalculator.CalculateContrastRatio(
            Colors.White, background);

        return blackContrast >= minRatio ? Colors.Black : Colors.White;
    }
}
```

## 6. Handle Errors Accessibly

Ensure validation errors are announced and programmatically associated:

```csharp
public class AccessibleFormField : SkiaStackLayout
{
    private SkiaLabel _label;
    private SkiaEntry _entry;
    private SkiaLabel _error;

    public AccessibleFormField(string labelText, string placeholder)
    {
        Spacing = 8;

        _label = new SkiaLabel
        {
            Text = labelText,
            AccessibleRole = AccessibleRole.Label
        };

        _entry = new SkiaEntry
        {
            Placeholder = placeholder,
            AccessibleName = labelText,
            AccessibleDescribedBy = "error_" + Guid.NewGuid()
        };

        _error = new SkiaLabel
        {
            TextColor = Colors.Red,
            IsVisible = false,
            AccessibleRole = AccessibleRole.Alert,
            AutomationId = _entry.AccessibleDescribedBy
        };

        Children.Add(_label);
        Children.Add(_entry);
        Children.Add(_error);
    }

    public void SetError(string message)
    {
        _error.Text = message;
        _error.IsVisible = true;
        _entry.States |= AccessibleStates.Invalid;
        _entry.RaiseAccessibilityEvent(AccessibleEvent.StateChanged);

        // Announce error to screen reader
        _error.RaiseAccessibilityEvent(AccessibleEvent.Alert);
    }

    public void ClearError()
    {
        _error.IsVisible = false;
        _entry.States &= ~AccessibleStates.Invalid;
        _entry.RaiseAccessibilityEvent(AccessibleEvent.StateChanged);
    }
}
```

## 7. Support Text Scaling

Respect user font size preferences:

```csharp
public class ScalableText : SkiaLabel
{
    private double _baseFontSize = 16;

    public ScalableText()
    {
        UpdateFontSize();

        // Monitor system font scale changes
        Application.Current.RequestedThemeChanged += (s, e) =>
        {
            UpdateFontSize();
        };
    }

    private void UpdateFontSize()
    {
        var scaleFactor = GetSystemTextScaleFactor();
        FontSize = _baseFontSize * scaleFactor;

        // Ensure minimum touch target size
        MinimumHeightRequest = Math.Max(44, FontSize * 1.5);
    }

    private double GetSystemTextScaleFactor()
    {
        // Read GNOME text scaling factor
        var gnomeScale = GSettings.GetDouble(
            "org.gnome.desktop.interface", "text-scaling-factor");
        return gnomeScale > 0 ? gnomeScale : 1.0;
    }
}
```

